import { currencySymbolMap, EMPTY_SET } from '../../const';
import { CurrencyFormatter } from '../formatter';

const cf = new CurrencyFormatter({
    pattern: 'D C',
    code: 'USD',
    decimal: 2,
    emptySet: EMPTY_SET,
    symbolMap: currencySymbolMap
});

export const formatUsCurrency = cf.format;

export const formatUsAmount = cf.amount;

export const getUsCurrencySymbol = cf.symbol;
